// 时间片轮转模拟
struct Process {
    int pid, burst_time, remaining_time;
};

void roundRobin(Process p[], int n, int quantum) {
    queue<int> ready;
    for (int i = 0; i < n; i++) ready.push(i);

    while (!ready.empty()) {
        int idx = ready.front(); ready.pop();
        int exec = min(quantum, p[idx].remaining_time);
        p[idx].remaining_time -= exec;
        if (p[idx].remaining_time > 0)
            ready.push(idx);  // 未完成，放回队尾
    }
}

