bool isSafe(int available[], int max[][N], 
            int alloc[][N], int need[][N]) {
    bool finish[N] = {false};
    int work[N];
    memcpy(work, available, sizeof(work));

    int count = 0;
    while (count < N) {
        bool found = false;
        for (int i = 0; i < N; i++) {
            if (!finish[i] && canSatisfy(need[i], work)) {
                for (int j = 0; j < N; j++)
                    work[j] += alloc[i][j];
                finish[i] = true;
                count++;
                found = true;
            }
        }
        if (!found) return false;  // 不安全
    }
