// LRU页面置换（双向链表+哈希表）
class LRUCache {
    list<int> lru_list;  // 最近使用的在前面
    unordered_map<int, list<int>::iterator> map;
    int capacity;
public:
    void access(int page) {
        if (map.count(page)) {
            lru_list.erase(map[page]);  // 移到前面
        } else if (lru_list.size() >= capacity) {
            int victim = lru_list.back();
            lru_list.pop_back();
            map.erase(victim);  // 淘汰
        }
        lru_list.push_front(page);
        map[page] = lru_list.begin();
    }
};

