// SCAN电梯算法
void scan(int requests[], int n, int head, bool direction) {
    sort(requests, requests + n);
    int distance = 0;

    if (direction) {  // 向大号方向
        for (int i = 0; i < n; i++) {
            if (requests[i] >= head) {
                distance += abs(requests[i] - head);
                head = requests[i];
            }
        }
        distance += abs(head - 199);  // 到边界
        head = 199;
        for (int i = n-1; i >= 0; i--) {
            if (requests[i] < 199) {
                distance += abs(head - requests[i]);
                head = requests[i];
            }
        }
    }
    cout << "总寻道距离: " << distance << endl;
}

