#include <semaphore.h>
#include <pthread.h>

#define N 10
int buffer[N];
int in = 0, out = 0;

sem_t empty, full, mutex;
// 初始化
sem_init(&empty, 0, N);  // N个空槽
sem_init(&full, 0, 0);   // 0个产品
sem_init(&mutex, 0, 1);  // 互斥

void* producer(void* arg) {
    int item;
    while (true) {
        item = produce();        // 生产
        sem_wait(&empty);        // 等待空槽
        sem_wait(&mutex);        // 加锁
        buffer[in] = item;
        in = (in + 1) % N;
        sem_post(&mutex);        // 解锁
        sem_post(&full);         // 通知消费者
    }
}

void* consumer(void* arg) {
    int item;
    while (true) {
        sem_wait(&full);         // 等待产品
        sem_wait(&mutex);        // 加锁
        item = buffer[out];
        out = (out + 1) % N;
        sem_post(&mutex);        // 解锁
        sem_post(&empty);        // 通知生产者
        consume(item);           // 消费
    }
}

