// 读取文件
void readFile(const char* filename) {
    int fd = open(filename, O_RDONLY);
    struct stat sb;
    fstat(fd, &sb);

    // 映射文件到内存
    char* addr = (char*)mmap(NULL, sb.st_size, PROT_READ, MAP_PRIVATE, fd, 0);

    // 像访问数组一样访问文件
    for (size_t i = 0; i < sb.st_size; i++) {
        putchar(addr[i]);
    }

    munmap(addr, sb.st_size);
    close(fd);
}

// 进程间共享内存
void sharedMemory() {
    int fd = shm_open("/myshm", O_CREAT | O_RDWR, 0666);
    ftruncate(fd, 4096);

    char* addr = (char*)mmap(NULL, 4096, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);

    // 进程A写入
    strcpy(addr, "Hello from Process A");

    // 进程B可以直接读取
    // printf("%s\n", addr);

    munmap(addr, 4096);
    shm_unlink("/myshm");
}

