// COW示意（概念性）
// fork前：父进程有数据页
// fork后：父子共享同一物理页（只读标记）

#include <unistd.h>
#include <sys/wait.h>

int main() {
    int data = 100;  // 父子进程共享此页

    pid_t pid = fork();

    if (pid == 0) {
        // 子进程：此时data与父进程共享物理内存
        printf("Child before modify: %d\n", data);

        // 写操作触发COW，复制该页
        data = 200;
        printf("Child after modify: %d\n", data);
    } else {
        wait(NULL);
        // 父进程的data不受影响
        printf("Parent: %d\n", data);  // 输出100
    }
}

