// RCU简化概念
// 实际RCU是Linux内核机制，用户空间可用类似思想

#include <atomic>
#include <memory>

template<typename T>
class RCUPtr {
    std::atomic<T*> ptr;
    std::atomic<int> readers{0};
public:
    T* read_lock() {
        readers++;
        return ptr.load();
    }

    void read_unlock() {
        readers--;
    }

    void update(T* newPtr) {
        T* old = ptr.exchange(newPtr);
        // 等待所有读者退出
        while (readers > 0) {
            std::this_thread::yield();
        }
        delete old;  // 安全删除
    }
};

