// C++17 NUMA-aware allocator（概念）
template<typename T>
struct NumaAllocator {
    int node;

    T* allocate(size_t n) {
        return (T*)numa_alloc_onnode(n * sizeof(T), node);
    }

    void deallocate(T* p, size_t n) {
        numa_free(p, n * sizeof(T));
    }
};

