// 错误示例：伪共享
struct CounterBad {
    std::atomic<int> count1;  // 可能在同一缓存行
    std::atomic<int> count2;  // 导致伪共享
};

// 正确示例：缓存行对齐，避免伪共享
// 缓存行通常64字节
class alignas(64) PaddedInt {
    std::atomic<int> value;
    // 编译器自动填充到64字节
};

struct CounterGood {
    PaddedInt count1;  // 独占一个缓存行
    PaddedInt count2;  // 独占另一个缓存行
};

// 手动padding方式
class alignas(64) AlignedCounter {
    std::atomic<int> value;
    char padding[64 - sizeof(std::atomic<int>)];
};

void benchmark() {
    const int N = 10000000;

    // 伪共享测试
    CounterBad bad;
    bad.count1 = 0;
    bad.count2 = 0;

    auto start = std::chrono::high_resolution_clock::now();
    std::thread t1([&]() { for (int i = 0; i < N; i++) bad.count1++; });
    std::thread t2([&]() { for (int i = 0; i < N; i++) bad.count2++; });
    t1.join(); t2.join();
    auto end = std::chrono::high_resolution_clock::now();

    std::cout << "False Sharing: "
              << std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count()
              << "ms" << std::endl;

    // 缓存行对齐测试
    CounterGood good;
    good.count1.value = 0;
    good.count2.value = 0;

    start = std::chrono::high_resolution_clock::now();
    std::thread t3([&]() { for (int i = 0; i < N; i++) good.count1.value++; });
    std::thread t4([&]() { for (int i = 0; i < N; i++) good.count2.value++; });
    t3.join(); t4.join();
    end = std::chrono::high_resolution_clock::now();

    std::cout << "Cache Line Aligned: "
              << std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count()
              << "ms" << std::endl;
}

#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        perror("fork failed");
        return 1;
    } else if (pid == 0) {
        // 子进程
        printf("Child: PID=%d, PPID=%d\n", getpid(), getppid());

        // 执行新程序
        execlp("ls", "ls", "-l", NULL);

        // execlp成功不返回，到这里说明失败
        perror("execlp failed");
        return 1;
    } else {
        // 父进程
        printf("Parent: PID=%d, Child PID=%d\n", getpid(), pid);

        int status;
        pid_t child_pid = wait(&status);  // 等待子进程结束

        if (WIFEXITED(status)) {
            printf("Child %d exited with code %d\n", 
                   child_pid, WEXITSTATUS(status));
        }
    }

    return 0;
}

#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>

void create_daemon() {
    // 1. 第一次fork
    pid_t pid = fork();
    if (pid < 0) exit(1);
    if (pid > 0) exit(0);  // 父进程退出

    // 2. 创建新会话
    if (setsid() < 0) exit(1);

    // 3. 第二次fork
    pid = fork();
    if (pid < 0) exit(1);
    if (pid > 0) exit(0);

    // 4. 改变工作目录
    chdir("/");

    // 5. 重设文件权限掩码
    umask(0);

    // 6. 关闭文件描述符
    for (int i = 0; i < 1024; i++) {
        close(i);
    }

    // 守护进程主逻辑
    while (1) {
        // 执行任务
        sleep(60);
    }
}
